import org.bouncycastle.jce.provider.BouncyCastleProvider;
import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.SecretKeySpec;

public class AESEncryptionUtil {
    private static final String AES = "AES";
    private static final String UTF_8 = "UTF-8";

    static {
        Security.addProvider(new BouncyCastleProvider());
    }

    public SecretKey generateSecretKey() throws Exception {
        KeyGenerator keyGen = KeyGenerator.getInstance(AES);
        keyGen.init(128);
        return keyGen.generateKey();
    }

    public SecretKey getKeyFromPassword(char[] password) {
        byte[] keyBytes = new byte[16];
        System.arraycopy(password, 0, keyBytes, 0, Math.min(password.length, keyBytes.length));
        return new SecretKeySpec(keyBytes, AES);
    }

    public String encrypt(SecretKey key, String data) throws Exception {
        Cipher cipher = Cipher.getInstance(AES + "/ECB/PKCS5Padding");
        cipher.init(Cipher.ENCRYPT_MODE, key);
        byte[] encryptedData = cipher.doFinal(data.getBytes(UTF_8));
        return Base64.encodeToString(encryptedData, Base64.DEFAULT);
    }

    public String decrypt(SecretKey key, String encryptedData) throws Exception {
        Cipher cipher = Cipher.getInstance(AES + "/ECB/PKCS5Padding");
        cipher.init(Cipher.DECRYPT_MODE, key);
        byte[] decryptedData = Base64.decode(encryptedData, Base64.DEFAULT);
        return new String(cipher.doFinal(decryptedData), UTF_8);
    }
}